import (
	context "context"
	fernclient "github.com/path-parameters/fern/client"
)

client := fernclient.NewClient()
response, err := client.Organizations.Getorganization(
	context.TODO(),
	"tenant_id",
	"organization_id",
)

import (
	context "context"
	fern "github.com/path-parameters/fern"
	fernclient "github.com/path-parameters/fern/client"
)

client := fernclient.NewClient()
response, err := client.User.Createuser(
	context.TODO(),
	"tenant_id",
	&fern.UserCreateUserRequest{
		Body: &fern.User{
			Name: "name",
			Tags: []string{
				"tags",
			},
		},
	},
)

